import subprocess, re

# Get all dynamic symbols with their addresses and sizes
result = subprocess.run(['readelf', '--dyn-syms', '-W', 'libmonosgen-2.0.so'], capture_output=True, text=True)
symbols = []
for line in result.stdout.splitlines():
    parts = line.split()
    if len(parts) >= 8:
        try:
            addr = int(parts[1], 16)
            size = int(parts[2])
            sym_type = parts[3]
            name = parts[7] if len(parts) > 7 else ''
            if addr > 0 and sym_type == 'FUNC' and name:
                symbols.append((addr, size, name))
        except (ValueError, IndexError):
            continue

symbols.sort(key=lambda x: x[0])

# Addresses to resolve (PC values from tombstone)
pcs = {
    'Thread 7020 (main) #01': 0x222098,
    'Thread 7020 (main) #02': 0x2241ac,
    'Thread 7020 (main) #03': 0x1abc80,
    'Thread 7020 (main) #04': 0x16de04,
    'Thread 7046 (SGen worker) #02': 0x2f4b20,
    'Thread 7046 (SGen worker) #03': 0x2f4c84,
    'Thread 7048 (Finalizer) #02': 0x2c1a40,
}

for label, pc in pcs.items():
    found = None
    for addr, size, name in symbols:
        if size > 0:
            if addr <= pc < addr + size:
                found = (name, pc - addr)
                break
        else:
            # Zero-size symbol: check if this is the closest preceding
            pass

    if not found:
        # Fallback: find the closest preceding symbol
        best = None
        for addr, size, name in symbols:
            if addr <= pc:
                best = (name, pc - addr)
            else:
                break
        found = best

    if found:
        print(f"  {label}: pc {hex(pc)} -> {found[0]}+{hex(found[1])}")
    else:
        print(f"  {label}: pc {hex(pc)} -> ??")
