from elftools.elf.elffile import ELFFile

with open('libmonosgen-2.0.so.dbg', 'rb') as f:
    elf = ELFFile(f)
    symtab = elf.get_section_by_name('.symtab')

    # Find all FUNC symbols, sorted by address
    funcs = []
    for sym in symtab.iter_symbols():
        if sym['st_info']['type'] == 'STT_FUNC' and sym['st_value'] > 0:
            funcs.append((sym['st_value'], sym['st_size'], sym.name))
    funcs.sort()

    # For the SGen worker addresses, find surrounding FUNC symbols
    for pc in [0x2f4b20, 0x2f4c84, 0x2c1a40]:
        # Find containing function
        found_containing = None
        for addr, size, name in funcs:
            if size > 0 and addr <= pc < addr + size:
                found_containing = (name, pc - addr, addr, size)
                break

        # Find nearest preceding
        nearest_before = None
        for addr, size, name in funcs:
            if addr <= pc:
                nearest_before = (name, pc - addr, addr, size)
            elif addr > pc:
                break

        print(f"PC 0x{pc:x}:")
        if found_containing:
            print(f"  Containing: {found_containing[0]} (base=0x{found_containing[2]:x}, size={found_containing[3]}, offset=+0x{found_containing[1]:x})")
        else:
            print(f"  No containing FUNC symbol")
        if nearest_before:
            print(f"  Nearest preceding: {nearest_before[0]} (base=0x{nearest_before[2]:x}, size={nearest_before[3]}, offset=+0x{nearest_before[1]:x})")
        print()

    # Also check: what OBJECT symbols (data) are at those addresses?
    print("Checking OBJECT symbols:")
    for sym in symtab.iter_symbols():
        if sym['st_value'] > 0 and sym['st_info']['type'] == 'STT_OBJECT':
            addr = sym['st_value']
            size = sym['st_size']
            if size > 0:
                for pc in [0x2f4b20, 0x2f4c84]:
                    if addr <= pc < addr + size:
                        print(f"  PC 0x{pc:x} in OBJECT {sym.name} (0x{addr:x}, size={size})")
